head.script:
scwin.statusFlag = "";
scwin.processFlag = "";
scwin.invoiceCheck = "0";
scwin.tabNo = 0;
scwin.mhnoFlag = "0";
scwin.hd_kcomcd = "DBEX";
scwin.userId = "";
scwin.vCurDate = "";
scwin.strPreDate = "";

scwin.onpageload = function() {
    scwin.vCurDate = WebSquare.date.getCurrentServerDate("yyyyMMdd");
    scwin.strPreDate = $c.date.addDay(scwin.vCurDate, -2);
    scwin.userId = $c.ses.getUserId();
    scwin.f_initSetTab();
    scwin.f_DefaultValue();
};

scwin.onUdcCompleted = function() {
    if (lc_seaAir.getValue() == "A") {
        scwin.f_BltypeDisable();
    } else {
        scwin.f_BltypeEnable();
    }
    scwin.f_Tab1Loading();
    chb_sub.setDisabled(true);
    scwin.f_Check();
    scwin.getMaxCloseYm();
};

scwin.getMaxCloseYm = async function() {
    dma_search2.set("coCd", "000");
    await $c.sbm.execute(sbm_getMaxCloseYm);
};

scwin.f_initSetTab = function() {
    // TODO: cfEnableObjects for tab - cfViewTab(0)
};

scwin.f_DefaultValue = function() {
    scwin.f_Set("INIT");
};

scwin.f_Check = function() {
    lc_gbDate.setSelectedIndex(0);
    lc_totalTab1.setValue("S");
    // TODO: lc_totalTab2 CodeValue = "S"
    lc_kindTab1.setSelectedIndex(0);
    lc_kindTab2.setSelectedIndex(0);
    // TODO: lc_blType Index = 0
    lc_seaAir.setFocus();
};

scwin.f_selectTabMenu = function(idx) {
    switch (idx) {
        case 0:
            scwin.tabNo = 0;
            scwin.f_TotalGroupChange();
            scwin.f_Tab1Loading();
            $c.gus.cfEnableObjects([lc_gbDate, cnd_ed_linerCd, cnd_txt_linerNm, cnd_ed_salesCd1, cnd_ed_salesCd2, cnd_ed_salesCd3, cnd_ed_picCd,
                cnd_txt_salesNm1, cnd_txt_salesNm2, cnd_txt_salesNm3, cnd_txt_picNm, cnd_ed_pnCd, cnd_txt_pnNm,
                cnd_ed_arCd, cnd_txt_arNm, cnd_ed_cntyCd, cnd_txt_cntyNm, cnd_ed_loadCd, cnd_txt_loadNm, cnd_ed_discCd,
                cnd_txt_discNm, lc_totalTab1, lc_kindTab1, lc_kindTab2]);
            chb_sub.setValue("");
            chb_sub.setDisabled(true);
            if (lc_totalTab1.getValue() == "S") {
                cnd_ed_picCd.setValue("");
                cnd_txt_picNm.setValue("");
                $c.gus.cfDisableObjects([cnd_ed_picCd, cnd_txt_picNm]);
            } else {
                $c.gus.cfEnableObjects([cnd_ed_picCd, cnd_txt_picNm]);
            }
            break;
        case 1:
            scwin.tabNo = 1;
            scwin.f_TotalGroupChange();
            scwin.f_Tab2Loading();
            $c.gus.cfEnableObjects([lc_gbDate, cnd_ed_linerCd, cnd_txt_linerNm, cnd_ed_salesCd1, cnd_ed_salesCd2, cnd_ed_salesCd3,
                cnd_txt_salesNm1, cnd_txt_salesNm2, cnd_txt_salesNm3, cnd_ed_pnCd, cnd_txt_pnNm,
                cnd_ed_arCd, cnd_txt_arNm, cnd_ed_cntyCd, cnd_txt_cntyNm, cnd_ed_loadCd, cnd_txt_loadNm, cnd_ed_discCd,
                cnd_txt_discNm, lc_totalTab1, lc_kindTab1, lc_kindTab2]);
            chb_sub.setValue("");
            $c.gus.cfDisableObjects([chb_sub, cnd_ed_picCd, cnd_txt_picNm]);
            break;
        case 2:
            scwin.tabNo = 2;
            $c.gus.cfDisableObjects([lc_gbDate, cnd_ed_linerCd, cnd_txt_linerNm, cnd_ed_salesCd1, cnd_ed_salesCd2, cnd_ed_salesCd3, cnd_ed_picCd,
                cnd_txt_salesNm1, cnd_txt_salesNm2, cnd_txt_salesNm3, cnd_txt_picNm, cnd_ed_pnCd, cnd_txt_pnNm,
                cnd_ed_arCd, cnd_txt_arNm, cnd_ed_cntyCd, cnd_txt_cntyNm, cnd_ed_loadCd, cnd_txt_loadNm, cnd_ed_discCd,
                cnd_txt_discNm, lc_totalTab1, lc_kindTab1, lc_kindTab2]);
            $c.gus.cfEnableObjects([chb_sub]);
            chb_sub.setValue("Y");
            scwin.f_CreateDateTime();
            break;
    }
};

scwin.f_Set = function(gubun) {
    switch (gubun) {
        case "INIT":
            if (scwin.tabNo == "0") {
                scwin.statusFlag = "I";
            } else if (scwin.tabNo == "1") {
                scwin.statusFlag = "I";
            }
            break;
        case "RETRIEVE":
            if (scwin.tabNo == "0") {
                scwin.statusFlag = "";
            } else if (scwin.tabNo == "1") {
                scwin.statusFlag = "";
            }
            break;
        case "SAVE":
            if (scwin.tabNo == "0") {
                scwin.f_Set("RETRIEVE");
            } else if (scwin.tabNo == "1") {
                scwin.f_Set("RETRIEVE");
            }
            break;
    }
};

scwin.f_Retrieve = async function() {
    let chk = await $c.gus.cfValidate([udc_resultDt]);
    if (!chk) {
        return;
    }

    if (!$c.gus.cfIsAfterDate(ds_retrieve.get("resultDtFrom"), ds_retrieve.get("resultDtTo"))) {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_048, ["Date From", "Date To"]);
        return false;
    }

    ds_retrieve.set("kcomcd", scwin.hd_kcomcd);
    ds_retrieve.set("inpid", scwin.userId);

    if (scwin.tabNo == "0") {
        let kindVal = lc_kindTab1.getValue();
        if (kindVal == "1") {
            scwin.f_performanceBiz("1");
        } else if (kindVal == "2") {
            scwin.f_performanceBiz("2");
        } else if (kindVal == "3") {
            scwin.f_performanceBiz("3");
        } else if (kindVal == "4") {
            scwin.f_performanceBiz("4");
        } else if (kindVal == "5") {
            scwin.f_performanceBiz("5");
        } else if (kindVal == "6") {
            scwin.f_performanceBiz("6");
        } else if (kindVal == "7") {
            scwin.f_performanceBiz("7");
        } else if (kindVal == "8") {
            scwin.f_performanceBiz("8");
        } else if (kindVal == "9") {
            scwin.f_performanceBiz("9");
        } else {
            scwin.f_performanceBiz("10");
        }
        ds_retrieve.set("flag", "1");
        await $c.sbm.execute(sbm_retrieveBiz);
    } else if (scwin.tabNo == "1") {
        let kindVal = lc_kindTab2.getValue();
        if (kindVal == "1") {
            scwin.f_performanceOper("1");
        } else if (kindVal == "2") {
            scwin.f_performanceOper("2");
        } else if (kindVal == "3") {
            scwin.f_performanceOper("3");
        } else {
            scwin.f_performanceOper("4");
        }
        ds_retrieve.set("flag", "2");
        await $c.sbm.execute(sbm_retrieveOper);
    } else if (scwin.tabNo == "2") {
        ds_retrieve.set("flag", "3");
        // TODO: ds_thirdForm.SubsumExpr / SortExpr - GAUCE specific
        await $c.sbm.execute(sbm_retrieveThird);
        scwin.f_CreateDateTime();
    }
};

scwin.f_SetRslts = async function() {
    let yyyy = ds_retrieve.get("resultDtFrom").substring(0, 4);
    let mm = ds_retrieve.get("resultDtFrom").substring(4, 6);
    let chkConfirm = yyyy + "년 " + mm + "월 자료를 집계 하시겠습니까?";
    let chk = await $c.win.confirm(chkConfirm);
    if (chk) {
        await $c.sbm.execute(sbm_saveThird);
    }
};

scwin.f_FieldClear = function() {
    lc_seaAir.setSelectedIndex(2);
    lc_iogb.setSelectedIndex(1);
    lc_gbDate.setSelectedIndex(0);
    ds_retrieve.set("resultDtFrom", scwin.strPreDate);
    ds_retrieve.set("resultDtTo", scwin.vCurDate);
    lc_totalTab1.setValue("S");
    // TODO: lc_totalTab2 CodeValue = "S"
    lc_kindTab1.setSelectedIndex(0);
    lc_kindTab2.setSelectedIndex(0);
    // TODO: lc_blType Index = 0

    $c.gus.cfInitObjects([cnd_ed_custCd, cnd_txt_custNm,
        cnd_ed_linerCd, cnd_txt_linerNm,
        cnd_ed_salesCd1, cnd_txt_salesNm1,
        cnd_ed_salesCd2, cnd_txt_salesNm2,
        cnd_ed_salesCd3, cnd_txt_salesNm3,
        cnd_ed_picCd, cnd_txt_picNm,
        cnd_ed_loadCd, cnd_txt_loadNm,
        cnd_ed_pnCd, cnd_txt_pnNm,
        cnd_ed_arCd, cnd_txt_arNm,
        cnd_ed_cntyCd, cnd_txt_cntyNm,
        cnd_ed_loadCd, cnd_txt_loadNm,
        cnd_ed_discCd, cnd_txt_discNm,
        cnd_ed_deptCd, cnd_txt_deptNm]);

    ds_performanceBiz.removeAll();
    ds_performanceOper.removeAll();
};

scwin.f_PopUp = function(disGubun, chgGubun) {
    switch (disGubun) {
        case "Customer":
            udc_cust.ilCommonPopUp(scwin.callbackCustomer,
                cnd_ed_custCd.getValue().trim(),
                cnd_txt_custNm.getValue(),
                chgGubun,
                '10',
                'Customer Code,Customer Name,Address1,Address2,Address3,Address4,Tel,,,CRN',
                '140,300,100,100,100,100,100,,,100',
                '8,9',
                null, '500', '500', null, null, null,
                "F",
                'Customer search,Customer Code,Customer Name');
            break;
        case "Partner":
            udc_pn.ilCommonPopUp(scwin.callbackPartner,
                cnd_ed_pnCd.getValue().trim(),
                cnd_txt_pnNm.getValue(),
                chgGubun,
                '10',
                'Customer Code,Customer Name,Address1,Address2,Address3,Address4,Tel,,,CRN',
                '140,300,100,100,100,100,100,,,100',
                '8,9',
                null, '500', '500', null, null, null,
                "F",
                'Partner search,Customer Code,Customer Name');
            break;
        case "Liner":
            udc_liner.ilCommonPopUp(scwin.callbackLiner,
                cnd_ed_linerCd.getValue().trim(),
                cnd_txt_linerNm.getValue(),
                chgGubun,
                '10',
                'Liner Code,Liner Name,Address1,Address2,Address3,Address4,Tel,,,CRN',
                '140,300,100,100,100,100,100,,,100',
                '8,9',
                null, '500', '500', null, null, null,
                "F",
                'Liner search,Liner Code,Liner Name');
            break;
    }
};

scwin.callbackCustomer = function(rtnList) {
    $c.gus.cfSetReturnValue(rtnList, cnd_ed_custCd, cnd_txt_custNm);
};

scwin.callbackPartner = function(rtnList) {
    $c.gus.cfSetReturnValue(rtnList, cnd_ed_pnCd, cnd_txt_pnNm);
};

scwin.callbackLiner = function(rtnList) {
