scwin.f_downExcelSheetBiz = async function() {
    let cntRow = ds_performanceBiz.getRowCount();
    if (cntRow != 0) {
        let totalVal = lc_totalTab1.getValue();
        let kindVal = lc_kindTab1.getValue();
        let sheetTitle = "";
        let kindNames = {"1":"Result","2":"Customer","3":"Department","4":"Liner","5":"Partner","6":"Area","7":"Country","8":"Loading","9":"Discharge","10":"Salesman"};
        let kindName = kindNames[kindVal] || "Salesman";
        let totalName = (totalVal == "S") ? "Sum" : "Detail";
        sheetTitle = "영업-" + kindName + "-" + totalName;
        let cfrm = await $c.win.confirm("Performance List(" + sheetTitle + ")를 EXCEL로 다운로드 받으시겠습니까?");
        if (cfrm) {
            $c.data.downloadGridViewExcel(gr_performanceBiz, {"fileName": sheetTitle + ".xlsx", "sheetName": sheetTitle});
        }
    } else {
        await $c.gus.cfAlertMsg(E_MSG_CM_WRN_002);
    }
};

scwin.f_downExcelSheetOper = async function() {
    let cntRow = ds_performanceOper.getRowCount();
    if (cntRow != 0) {
        let totalVal = ds_retrieve.get("sumDetail");
        let kindVal = lc_kindTab2.getValue();
        let sheetTitle = "";
        let kindNames = {"1":"Customer","2":"Department","3":"Liner","4":"Area","5":"Port"};
        let kindName = kindNames[kindVal] || "Port";
        let totalName = (totalVal == "S") ? "Group별" : "월별";
        sheetTitle = "(물동량-" + kindName + "-" + totalName + ")";
        let cfrm = await $c.win.confirm("Performance List" + sheetTitle + "를 EXCEL로 다운로드 받으시겠습니까?");
        if (cfrm) {
            $c.data.downloadGridViewExcel(gr_performanceOper, {"fileName": sheetTitle + ".xlsx", "sheetName": sheetTitle});
        }
    } else {
        await $c.gus.cfAlertMsg(E_MSG_CM_WRN_002);
    }
};

scwin.f_gridFormatBiz = function(gubun1) {
    // TODO: Dynamic grid format change - GAUCE gr_performanceBiz.Format
    // WebSquare gridView does not support runtime Format string change.
    // Grid columns are statically defined in XML body.
    // The original GAUCE code dynamically changed grid columns per gubun1 (1~20).
    // In WebSquare, this requires either:
    //   (a) Multiple gridViews with visibility toggle, or
    //   (b) Runtime column show/hide via API
    // Keeping as TODO for manual implementation.
};

scwin.f_gridFormatOper = function(gubun1) {
    // TODO: Dynamic grid format change - GAUCE gr_performanceOper.Format
    // Same as f_gridFormatBiz - requires manual implementation for WebSquare.
};

