scwin.f_performanceOper = function(gubun1) {
    switch (gubun1) {
        case "1":
            if (ds_retrieve.get("sumDetail") == "S") {
                scwin.f_gridFormatOper("1");
            } else {
                scwin.f_gridFormatOper("2");
            }
            break;
        case "2":
            if (ds_retrieve.get("sumDetail") == "S") {
