scwin.f_houseBlLoadingBiz = async function(row) {
    let param1 = lc_seaAir.getValue();
    let param2 = lc_iogb.getValue();
    let param3 = ds_retrieve.get("resultDtFrom");
    let param4 = ds_retrieve.get("resultDtTo");
    let param5 = "";
    if (lc_kindTab1.getValue() == "1") {
        param5 = ds_performanceBiz.getCellData(row, "vcol02");
    } else {
        param5 = ds_performanceBiz.getCellData(row, "vcol04");
    }
    let param6 = cnd_ed_loadCd.getValue();
    let param7 = cnd_txt_loadNm.getValue();
    let param8 = cnd_ed_cntyCd.getValue();
    let param9 = cnd_txt_cntyNm.getValue();
    let param10 = ds_retrieve.get("itemCd");
