scwin.f_TotalGroupChange = function() {
    if (scwin.tabNo == "0") {
        if (lc_totalTab1.getValue() == "S") {
            cnd_ed_picCd.setValue("");
            cnd_txt_picNm.setValue("");
            $c.gus.cfDisableObjects([cnd_ed_picCd, cnd_txt_picNm]);
        } else {
            $c.gus.cfEnableObjects([cnd_ed_picCd, cnd_txt_picNm]);
        }
        let kindVal = lc_kindTab1.getValue();
        let totalVal = lc_totalTab1.getValue();
        if (kindVal == "1") {
            if (totalVal == "S") { scwin.f_gridFormatBiz("1"); } else { scwin.f_gridFormatBiz("2"); }
        } else if (kindVal == "2") {
            if (totalVal == "S") { scwin.f_gridFormatBiz("3"); } else { scwin.f_gridFormatBiz("4"); }
        } else if (kindVal == "3") {
            if (totalVal == "S") { scwin.f_gridFormatBiz("5"); } else { scwin.f_gridFormatBiz("6"); }
        } else if (kindVal == "4") {
            if (totalVal == "S") { scwin.f_gridFormatBiz("7"); } else { scwin.f_gridFormatBiz("8"); }
        } else if (kindVal == "5") {
            if (totalVal == "S") { scwin.f_gridFormatBiz("9"); } else { scwin.f_gridFormatBiz("10"); }
        } else if (kindVal == "6") {
            if (totalVal == "S") { scwin.f_gridFormatBiz("11"); } else { scwin.f_gridFormatBiz("12"); }
        } else if (kindVal == "7") {
            if (totalVal == "S") { scwin.f_gridFormatBiz("13"); } else { scwin.f_gridFormatBiz("14"); }
        } else if (kindVal == "8") {
            if (totalVal == "S") { scwin.f_gridFormatBiz("15"); } else { scwin.f_gridFormatBiz("16"); }
        } else if (kindVal == "9") {
            if (totalVal == "S") { scwin.f_gridFormatBiz("17"); } else { scwin.f_gridFormatBiz("18"); }
        } else if (kindVal == "10") {
            if (totalVal == "S") { scwin.f_gridFormatBiz("19"); } else { scwin.f_gridFormatBiz("20"); }
        }
        ds_performanceBiz.removeAll();
    } else if (scwin.tabNo == "1") {
        let kindVal = lc_kindTab2.getValue();
        let totalVal = ds_retrieve.get("sumDetail");
        if (kindVal == "1") {
            if (totalVal == "S") { scwin.f_gridFormatOper("1"); } else { scwin.f_gridFormatOper("2"); }
        } else if (kindVal == "2") {
            if (totalVal == "S") { scwin.f_gridFormatOper("3"); } else { scwin.f_gridFormatOper("4"); }
        } else if (kindVal == "3") {
            if (totalVal == "S") { scwin.f_gridFormatOper("5"); } else { scwin.f_gridFormatOper("6"); }
        } else if (kindVal == "4") {
            if (totalVal == "S") { scwin.f_gridFormatOper("7"); } else { scwin.f_gridFormatOper("8"); }
        } else if (kindVal == "5") {
            if (totalVal == "S") { scwin.f_gridFormatOper("9"); } else { scwin.f_gridFormatOper("10"); }
        }
        ds_performanceOper.removeAll();
    }
};

