scwin.sbm_getMaxCloseYm_submitdone = function(e) {
    let thisYm = scwin.vCurDate;
    if (ds_getMaxCloseYm.getRowCount() > 0) {
        let closeYm = ds_getMaxCloseYm.getCellData(0, "closeYm");
        if (closeYm != thisYm.substr(0, 6)) {
            let firstDay = closeYm.substr(0, 4) + "/" + closeYm.substr(4, 2) + "/" + "01";
            let lastDayNum = new Date(parseInt(closeYm.substr(0, 4)), parseInt(closeYm.substr(4, 2)), 0).getDate();
            let lastDay = closeYm.substr(0, 4) + "/" + closeYm.substr(4, 2) + "/" + (lastDayNum < 10 ? "0" + lastDayNum : lastDayNum);
            ds_retrieve.set("resultDtTo", lastDay.replace(/\//g, ""));
            ds_retrieve.set("resultDtFrom", firstDay.replace(/\//g, ""));
        } else {
            let firstDay = thisYm.substr(0, 4) + "/" + thisYm.substr(4, 2) + "/" + "01";
            let lastDayNum = new Date(parseInt(thisYm.substr(0, 4)), parseInt(thisYm.substr(4, 2)), 0).getDate();
            let lastDay = thisYm.substr(0, 4) + "/" + thisYm.substr(4, 2) + "/" + (lastDayNum < 10 ? "0" + lastDayNum : lastDayNum);
            ds_retrieve.set("resultDtTo", lastDay.replace(/\//g, ""));
            ds_retrieve.set("resultDtFrom", firstDay.replace(/\//g, ""));
        }
    }
};

