scwin.gr_performanceBiz_oncelldblclick = function(rowIndex, columnIndex, columnId) {
    if (rowIndex >= 0) {
        let kindVal = lc_kindTab1.getValue();
        let totalVal = lc_totalTab1.getValue();
        if (kindVal == "1" && totalVal == "D") {
            let vcol04 = ds_performanceBiz.getCellData(rowIndex, "vcol04");
            if (vcol04 == "" || vcol04 == "계 " || vcol04 == "합계 ") {
                return;
            } else {
                let param = {
                    kcomcd: scwin.hd_kcomcd,
                    seaair: ds_performanceBiz.getCellData(rowIndex, "vcol01"),
                    iogb: "",
                    blno: vcol04,
                    mblno: "",
                    mhno: ""
                };
                $c.win.openMenu("Booking Sheet", "/ui/il/pfm/pfbs/pe_101_01_01b.xml", "pe_101_01_01b.xml", param);
            }
        } else if (totalVal == "D") {
            let vcol05 = ds_performanceBiz.getCellData(rowIndex, "vcol05");
            if (vcol05 == "" || vcol05 == "계 " || vcol05 == "합계 ") {
                return;
            } else {
                let param = {
                    kcomcd: scwin.hd_kcomcd,
                    seaair: ds_performanceBiz.getCellData(rowIndex, "vcol01"),
                    iogb: "",
                    blno: vcol05,
                    mblno: "",
                    mhno: ""
                };
                $c.win.openMenu("Booking Sheet", "/ui/il/pfm/pfbs/pe_101_01_01b.xml", "pe_101_01_01b.xml", param);
            }
        }
    }
};
